437	class AttributeGuard {
438	public:
439		AttributeGuard(RTLILBuilder &builder)
440			: builder(builder)
441		{
442			save.swap(builder.staged_attributes);
443			save_source_range = builder.staged_source_range;
444			save_source_range_valid = builder.staged_source_range_valid;
445			builder.staged_source_range_valid = false;
446		}
447	
448		~AttributeGuard()
449		{
450			save.swap(builder.staged_attributes);
451			builder.staged_source_range = save_source_range;
452			builder.staged_source_range_valid = save_source_range_valid;
453		}
454	
455		void set(RTLIL::IdString id, RTLIL::Const value)
456		{
457			builder.staged_attributes[id] = value;
458		}
459	
460		void set_source(slang::SourceRange source_range)
461		{
462			builder.staged_source_range = source_range;
463			builder.staged_source_range_valid = true;
464		}
465	
466	private:
467		RTLILBuilder &builder;
468		Yosys::dict<RTLIL::IdString, RTLIL::Const> save;
