		log("netlist form.\n");
		log("\n");
		for (auto& opt : driver.cmdLine.getHelpOptions()) { 
			log("    %s\n", opt.first.c_str());
			log("        %s\n",wrap_text(opt.second).c_str());
			log("\n");
		}

